import React, { useRef, useState } from "react";
import { Grid, Button, Typography, Paper, TextField } from "@material-ui/core";

import { makeStyles } from "@material-ui/core/styles";
import Grow from "@material-ui/core/Grow";

const useStyles = makeStyles((theme) => ({
  root: {
    height: "100vh",
    justifyContent: "center",
    alignItems: "center",
    display: "flex",
  },
  paper: {
    padding: theme.spacing(4),
    width: 400,
    elevation: 4,
  },
  title: {
    marginBottom: theme.spacing(2),
    textAlign: "center",
  },
  textField: {
    marginBottom: theme.spacing(2),
  },
}));

export default function Login() {
  const nodeRef = useRef(null);

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [snackbarOpen, setSnackbarOpen] = useState(false);
  const [snackbarMessage, setSnackbarMessage] = useState("");
  const [checked, setChecked] = useState(true);

  const handleLogin = () => {
    // Add login logic here (validation, API call, etc.)
    if (!email || !password) {
      setSnackbarMessage("Please enter both email and password");
      setSnackbarOpen(true);
      return;
    }
    // Call your backend login API here
  };

  return (
    <Grid container>
      <Grow in={checked} nodeRef={nodeRef} timeout={500}>
        <div ref={nodeRef}>
          <Paper>
            <Typography variant="h5">Login</Typography>
            <TextField
              label="Email"
              type="email"
              fullWidth
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
            <TextField
              label="Password"
              type="password"
              fullWidth
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
            <Button
              variant="contained"
              color="primary"
              fullWidth
              onClick={handleLogin}
            >
              Sign In
            </Button>
          </Paper>
        </div>
      </Grow>
    </Grid>
  );
}
